import { Component, ViewChild } from '@angular/core';
import { FormGroup, FormBuilder, Validators, FormControl } from '@angular/forms';
import { MatPaginator } from '@angular/material/paginator';
import { MatSort } from '@angular/material/sort';
import { debounce, debounceTime, delay, map, merge, startWith, switchMap, tap } from 'rxjs';
import { ApiService } from '@services/api.service';

@Component({
  selector: 'app-orders-list',
  templateUrl: './orders-list.component.html',
  styleUrls: ['./orders-list.component.scss']
})

export class OrdersListComponent {
  
  query: string = "";
  filterForm: FormGroup;
  isLoadingResults = true;

  displayedColumns: string[] = ['order_id', 'createdAt', 'store_name', 'Customer Name', 'Total Amount', 'Order Status', 'Action'];
  data : Orders[] = [];
  resultsLength = 0;
  sortBy: string = 'order_id'
  stores: string[] = [];

  orderStatuses = new FormControl('');
  orderStatusList: string[] = ['received', 'in progress', "ready for pickup", 'in transit', 'completed', 'cancelled', 'return request', 'return cancelled', 'returned'];

  @ViewChild(MatPaginator) paginator: MatPaginator;
  @ViewChild(MatSort) sort: MatSort;

  ngOnInit(): void {

  }
  
  constructor(private api: ApiService, private fb: FormBuilder) {
    this.filterForm = this.fb.group({
      order_id: [null, []],
      store_id: [null, []],
      from_date: [null, []],
      to_date: [new Date(), [Validators.required]],
      order_statuses: this.orderStatuses
    })

    this.filterForm.valueChanges.pipe(
      tap(() => this.isLoadingResults = true),
      debounceTime(1000),
    ).subscribe(() => {
      const {order_id, store_id, from_date, to_date, order_statuses} = this.filterForm.value;
        this.api.orderList(order_id,store_id ? store_id: null, this.paginator.pageIndex + 1, this.paginator.pageSize, this.sort.active, this.sort.direction, from_date, to_date, null, order_statuses ? order_statuses.map(os => {return {order_status_name: os}}) : []).subscribe((data: any) => {
        this.isLoadingResults = false;
        if (data === null) {
          return [];
        }
  
        this.resultsLength = data.total_count;
        this.data = data.orders.map((order:any) => {
          return {
            order_id: order.order_id,
            store_id: order.store.store_id,
            store_name: order.store.store_name,
            customer_name: order.customer_name,
            total_amount: order.total_amount,
            order_status_name: order.order_histories[0].order_status.order_status_name,
            createdAt: order.createdAt

          }
        });
      })
    })
  }

  ngAfterViewInit() {
    this.sort.sortChange.subscribe(() => {
      this.paginator.pageIndex = 0
    });

    merge(this.sort.sortChange, this.paginator.page)
      .pipe(
        startWith({}),
        switchMap(() => {
          this.isLoadingResults = true;
          const {order_id, store_id, from_date, to_date, order_statuses} = this.filterForm.value;
          //store_id, page, page_size, order_by, order_type, from_date, to_date, only_active_orders, order_statuses
          return this.api.orderList(order_id, store_id, this.paginator.pageIndex + 1, this.paginator.pageSize, this.sort.active, this.sort.direction,from_date, to_date, null, order_statuses? order_statuses.map(os => {return {order_status_name: os}}) : []);
        }),
        map((data: any) => {
          this.isLoadingResults = false;
          // Flip flag to show that loading has finished.
          if (data === null) {
            return [];
          }

          this.resultsLength = data.total_count;
          return data.orders.map((order:any) => {
        
            return {
              order_id: order.order_id,
              store_id: order.store.store_id,
              store_name: order.store.store_name,
              customer_name: order.customer_name,
              total_amount: order.total_amount,
              order_status_name: order.order_histories[0].order_status.order_status_name,
              createdAt: order.createdAt
            }
          });
        }),
      )
      .subscribe(data => this.data = data);

  }


}



export interface Orders {
  order_id: string,
  store_id: string,
  store_name: string,
  customer_name: string,
  total_amount: number,
  order_status_name: string
  createdAt: Date
}

